import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"16. Discipline","description":"","frontmatter":{"title":"16. Discipline","eba":"Biomedical Engineers 2025-2028","topics":["discipline","union-matters"]},"headers":[],"relativePath":"ebas/biomedical-engineers/consultation-disputes/16-discipline.md","filePath":"ebas/biomedical-engineers/consultation-disputes/16-discipline.md"}'),r={name:"ebas/biomedical-engineers/consultation-disputes/16-discipline.md"};function s(a,e,p,l,c,h){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_16-discipline" tabindex="-1">16. Discipline <a class="header-anchor" href="#_16-discipline" aria-label="Permalink to &quot;16. Discipline&quot;">​</a></h1><p><strong>16.1</strong> Application</p><p><strong>(a)</strong> Except as provided at 16.1(e), where an Employer has concerns about:</p><p><strong>(i)</strong> the Conduct of an Employee; or</p><p><strong>(ii)</strong> a Performance issue that may constitute Misconduct, the following procedure will apply.</p><p><strong>(b)</strong> There are two steps in a disciplinary process under this clause as follows:</p><p><strong>(i)</strong> investigative procedure; and</p><p><strong>(ii)</strong> disciplinary procedure.</p><p><strong>(c)</strong> An Employee will be provided a reasonable opportunity to be represented at any time (including by a Union) with respect to all matters set out in this clause.</p><p><strong>(d)</strong> The Employer will notify the Employee in accordance with subclause 16.3(b) as soon as practicable following the Employer becoming aware of the alleged concerns at subclause 16.1(a).</p><p><strong>(e)</strong> Exception - Employees who have not completed a minimum period of employment with their Employer Where an Employee has not completed a period of employment with their Employer of at least the minimum employment period defined at section 383 of the Act, and the Employer is considering the termination of the Employee&#39;s employment, the Employer will:</p><p><strong>(i)</strong> provide the concerns in writing to the Employee as soon as practicable following the Employer becoming aware of the alleged concerns;</p><p><strong>(ii)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(iii)</strong> other than in the case of Serious Misconduct, provide the Employee with an opportunity to improve their Performance or Conduct;</p><p><strong>(iv)</strong> meet with the Employee (and, where relevant, their representative); and</p><p><strong>(v)</strong> consider any explanation by the Employee including any matters raised in mitigation before making a decision to terminate the employment.</p><p>The terms of clause 16.3 to 16.5 inclusive do not apply to Employees within the scope of the exception in this clause 16.1(e).</p><p><strong>16.2</strong> Definitions</p><p><strong>(a)</strong> Conduct means the manner in which the Employee&#39;s behaviour impacts on their work.</p><p><strong>(b)</strong> Misconduct means an Employee&#39;s intentional or negligent failure to abide by or adhere to the standards of conduct expected by the Employer. A Performance issue can be considered misconduct where, despite all reasonably practicable interventions by the Employer, the Employee is unable to fulfil all or part of their job requirements to a satisfactory level.</p><p><strong>(c)</strong> Performance means the manner in which the Employee fulfils their job requirements. The level of performance is determined by reference to an Employee&#39;s knowledge, skills, qualifications, abilities and the requirements of the role.</p><p><strong>(d)</strong> Serious Misconduct is as defined under the Act and that is both wilful and deliberate. Currently the Act defines serious misconduct, in part, as:</p><p><strong>(i)</strong> wilful or deliberate behaviour by an employee that is inconsistent with the continuation of the contract of employment;</p><p><strong>(ii)</strong> conduct that causes serious and imminent risk to: <strong>(A)</strong> the health or safety of a person; or <strong>(B)</strong> the reputation, viability or profitability of the employer’s business. Conduct that is serious misconduct includes each of the following:</p><p><strong>(iii)</strong> the Employee, in the course of the Employee&#39;s employment, engaging in: <strong>(A)</strong> theft; <strong>(B)</strong> fraud; <strong>(C)</strong> assault; or <strong>(D)</strong> sexual harassment;</p><p><strong>(iv)</strong> the Employee being intoxicated at work;</p><p><strong>(v)</strong> the Employee refusing to carry out a lawful and reasonable instruction that is consistent with the Employee&#39;s contract of employment. Subclauses 16.2(d)(iii)-16.2(d)(v) do not apply if the Employee is able to show that, in the circumstances, the conduct engaged in by the Employee was not conduct that made employment in the period of notice unreasonable.</p><p><strong>16.3</strong> Investigative procedure</p><p><strong>(a)</strong> The purpose of an investigative procedure is to conclude whether, on balance, concerns regarding Conduct or Performance are well-founded and supported by evidence. An investigation procedure must be fair including proper regard to procedural fairness.</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> advise the Employee of the concerns and allegations in writing;</p><p><strong>(ii)</strong> provide the Employee with any material which forms the basis of the concerns before seeking a response;</p><p><strong>(iii)</strong> ensure the Employee is provided a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iv)</strong> advise the Employee of their right to have a representative, including a Union representative;</p><p><strong>(v)</strong> ensure that the reason for any interview is explained; and</p><p><strong>(vi)</strong> take reasonable steps to investigate the Employee&#39;s response.</p><p><strong>(c)</strong> Where the Employer has complied with subclause 16.3(b)(i)-(iv) and the Employee does not dispute the concerns, the Employee may opt to decline the opportunity to be interviewed.</p><p><strong>(d)</strong> Where the Employee opts to decline the opportunity to be interviewed, the Employee may still raise matters under clause 16.4(c) including matters in mitigation if a disciplinary procedure (see clause 16.4) is proposed.</p><p><strong>16.4</strong> Procedure to address Misconduct or Serious Misconduct</p><p><strong>(a)</strong> This procedure applies if, following the investigation, the Employer reasonably considers that the Employee&#39;s Conduct or Performance may warrant disciplinary steps being taken.</p><p><strong>(b)</strong> The Employer will:</p><p><strong>(i)</strong> notify the Employee in writing of the outcome of the investigation process, including the basis of any conclusion; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to provide information about the matters in 16.4(c).</p><p><strong>(c)</strong> In considering whether to take disciplinary action, the Employer will consider:</p><p><strong>(i)</strong> whether there is a valid reason related to the Conduct or Performance of the Employee arising from the investigation justifying disciplinary action;</p><p><strong>(ii)</strong> whether the Employee knew or ought to have known that the Conduct or Performance was below acceptable standards; and</p><p><strong>(iii)</strong> any explanation by the Employee relating to Conduct including any matters raised in mitigation.</p><p><strong>16.5</strong> Possible outcomes</p><p><strong>(a)</strong> Where, after following the procedures in this clause, it is determined that the Employee has engaged in Misconduct or Serious Misconduct and disciplinary action is warranted, the Employer may take disciplinary action which shall be recorded on the Employee&#39;s personnel file, as follows:</p><p><strong>(i)</strong> where the Performance or Conduct issue constitutes Misconduct but does not constitute Serious Misconduct, disciplinary action will be taken in accordance with the following steps: <strong>(A)</strong> counsel the Employee; <strong>(B)</strong> give the Employee a first written warning in the event that the Employee has been counselled within the previous 12 months for that course of Conduct or Performance issue. The Employer may also give the Employee a first written warning where the seriousness of the conduct is such that counselling the Employee under subclause 16.5(a)(i)(A) is not appropriate.</p><p><strong>(C)</strong> give the Employee a second written warning in the event that the Employee has previously been given a first written warning within the previous 12 months for that course of Conduct or Performance issue; <strong>(D)</strong> give the Employee a final written warning in the event that the Employee has previously been given a second written warning within the preceding 18-month period for that course of Conduct or Performance Issue; and <strong>(E)</strong> terminate the Employee&#39;s employment with notice in the case of an Employee who repeats a course of Conduct or Performance issue for which a final warning was given in the preceding 18 months;</p><p><strong>(ii)</strong> where the Performance or Conduct issue constitutes Serious Misconduct: <strong>(A)</strong> terminate the Employee&#39;s employment without notice; or <strong>(B)</strong> alternatively, issue the Employee with a final warning without following the steps in subclause 16.5(a)(i) above.</p><p><strong>(b)</strong> The Employer&#39;s decision and a summary of its reasons will be notified to the Employee in writing.</p><p><strong>(c)</strong> If after any warning or counselling, a period of 12 or 18 months elapses (as relevant) without the Employee repeating a course of Conduct or Performance Issue for which the preceding warning or counselling was given, the Employer cannot rely on the preceding warning or counselling for the purpose of issuing a further warning.</p><p><strong>16.6</strong> Disputes A dispute over the clause (including sub-clause 16.5) is to be dealt with in accordance with the Dispute Resolution Procedure of this Agreement.</p><p><strong>16.7</strong> Performance Management Nothing in this clause 16 will prevent the Employer from undertaking performance management to support Employees in accordance with <a href="/eba/ebas/allied-health/consultation-disputes/15-performance-management.html">clause 15</a> - Performance Management.</p><p>PART C TYPES OF EMPLOYMENT, COMMENCEMENT OF EMPLOYMENT AND END OF EMPLOYMENT</p>',57)])])}const m=t(r,[["render",s]]);export{d as __pageData,m as default};
